{
  "name": "rss-ai-to-slack",
  "nodes": {
    "feed": {
      "type": "producer",
      "source": "rss",
      "config": {
        "url": "https://example.com/feed.xml",
        "pollIntervalMs": 60000
      }
    },
    "ai_articles": {
      "type": "derived",
      "deps": ["feed"],
      "fn": "filterBy",
      "config": {
        "field": "title",
        "op": "contains",
        "value": "AI"
      }
    },
    "titles": {
      "type": "derived",
      "deps": ["ai_articles"],
      "fn": "mapFields",
      "config": {
        "mapping": {
          "title": "title"
        }
      }
    },
    "notify_slack": {
      "type": "effect",
      "deps": ["titles"],
      "fn": "sendSlackMessage",
      "config": {
        "channel": "#ai-news"
      }
    }
  }
}

type RssArticle = {
  title: string;
  text: string;
};

async function fetchRssFeed(url: string): Promise<any> {
  return fetchFromApi(url);
}

function parseRssArticles(feed: any): RssArticle[] {
  if (typeof feed === "string") {
    return parseRssXml(feed);
  }

  if (Array.isArray(feed?.items)) {
    return feed.items.map((item: any) => ({
      title: String(item.title ?? "").trim(),
      text: `${item.title ?? ""} ${item.description ?? ""} ${item.content ?? ""}`.trim(),
    }));
  }

  return [];
}

function parseRssXml(xml: string): RssArticle[] {
  const itemBlocks = [
    ...xml.matchAll(/<item\b[\s\S]*?<\/item>/gi),
    ...xml.matchAll(/<entry\b[\s\S]*?<\/entry>/gi),
  ].map((m) => m[0]);

  return itemBlocks.map((block) => {
    const title = extractTag(block, "title");
    const description = extractTag(block, "description");
    const content = extractTag(block, "content");
    const summary = extractTag(block, "summary");
    const text = `${title} ${description} ${content} ${summary}`.trim();
    return { title, text };
  });
}

function extractTag(block: string, tag: string): string {
  const match = block.match(new RegExp(`<${tag}\\b[^>]*>([\\s\\S]*?)<\\/${tag}>`, "i"));
  return decodeXml((match?.[1] ?? "").replace(/<!\[CDATA\[([\s\S]*?)\]\]>/gi, "$1").trim());
}

function decodeXml(value: string): string {
  return value
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function filterAiArticles(articles: RssArticle[]): RssArticle[] {
  return filterBy(articles, (a) => /\bai\b/i.test(a.text));
}

async function sendTitlesToSlack(channel: string, articles: RssArticle[]): Promise<void> {
  for (const article of articles) {
    await sendSlackMessage(channel, article.title);
  }
}

async function processRssFeedForAi(url: string, slackChannel: string): Promise<void> {
  const feed = await fetchRssFeed(url);
  const articles = parseRssArticles(feed);
  const aiArticles = filterAiArticles(articles);
  await sendTitlesToSlack(slackChannel, aiArticles);
}

{
  "name": "transactions-usd-to-eur-csv",
  "nodes": {
    "transactionsCsv": {
      "type": "producer",
      "source": "filesystem-watch",
      "config": {
        "path": "/data/incoming",
        "glob": "transactions.csv",
        "recursive": false
      }
    },
    "convertAmounts": {
      "type": "derived",
      "deps": [
        "transactionsCsv"
      ],
      "fn": "transformPayload",
      "config": {
        "rate": 0.92,
        "template": "Parse CSV rows and convert each amount from USD to EUR using eur_amount = usd_amount * rate"
      }
    },
    "resultCsv": {
      "type": "derived",
      "deps": [
        "convertAmounts"
      ],
      "fn": "formatResults",
      "config": {
        "format": "csv"
      }
    },
    "writeOutput": {
      "type": "effect",
      "deps": [
        "resultCsv"
      ],
      "fn": "writeLog",
      "config": {
        "destination": "/data/outgoing/transactions_eur.csv",
        "level": "info"
      }
    }
  }
}

async function convertTransactionsUsdToEurCsv(
  inputPath: string,
  outputPath: string,
  usdToEurRate: number = 0.92
): Promise<void> {
  const input = await readFile(inputPath);
  const rows = parseCsv(input);

  if (rows.length === 0) {
    throw new Error("CSV is empty.");
  }

  const header = [...rows[0]];
  const amountColIndex = findAmountUsdColumnIndex(header);

  if (amountColIndex === -1) {
    throw new Error(
      "Could not find USD amount column. Expected one of: amount_usd, usd_amount, amount."
    );
  }

  header[amountColIndex] = "amount_eur";

  const convertedRows = rows.slice(1).map((row) => {
    const next = [...row];
    const raw = (next[amountColIndex] ?? "").replace(/[$,\s]/g, "");
    const usd = Number.parseFloat(raw);

    if (!Number.isFinite(usd)) {
      throw new Error(`Invalid USD amount: "${next[amountColIndex]}"`);
    }

    next[amountColIndex] = (usdToEurRate * usd).toFixed(2);
    return next;
  });

  const outputCsv = toCsv([header, ...convertedRows]);
  await writeFile(outputPath, outputCsv);
}

function findAmountUsdColumnIndex(header: string[]): number {
  const normalized = header.map((h) => h.trim().toLowerCase());
  const candidates = ["amount_usd", "usd_amount", "amount"];
  for (const c of candidates) {
    const idx = normalized.indexOf(c);
    if (idx !== -1) return idx;
  }
  return -1;
}

function parseCsv(content: string): string[][] {
  const rows: string[][] = [];
  const lines = content.split(/\r?\n/).filter((line) => line.length > 0);
  for (const line of lines) {
    rows.push(parseCsvLine(line));
  }
  return rows;
}

function parseCsvLine(line: string): string[] {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const ch = line[i];

    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === "," && !inQuotes) {
      fields.push(current);
      current = "";
    } else {
      current += ch;
    }
  }

  fields.push(current);
  return fields;
}

function toCsv(rows: string[][]): string {
  return rows
    .map((row) => row.map(escapeCsvField).join(","))
    .join("\n");
}

function escapeCsvField(value: string): string {
  if (value == null) return "";
  const mustQuote = /[",\n]/.test(value);
  const escaped = value.replace(/"/g, '""');
  return mustQuote ? `"${escaped}"` : escaped;
}

{
  "name": "access-log-to-daily-report",
  "nodes": {
    "access_log": {
      "type": "producer",
      "source": "filesystem-watch",
      "config": {
        "path": "/var/log/nginx/access.log",
        "glob": "access.log",
        "recursive": false
      }
    },
    "parsed_request": {
      "type": "derived",
      "deps": ["access_log"],
      "fn": "parseLogLine",
      "config": {
        "format": "clf"
      }
    },
    "summary_row": {
      "type": "derived",
      "deps": ["parsed_request"],
      "fn": "mapFields",
      "config": {
        "mapping": {
          "date": "timestamp",
          "method": "method",
          "path": "path",
          "status": "status"
        }
      }
    },
    "append_to_spreadsheet": {
      "type": "effect",
      "deps": ["summary_row"],
      "fn": "writeToDB",
      "config": {
        "table": "daily_report_spreadsheet",
        "upsert": false
      }
    }
  }
}

type RequestLog = {
  timestamp: Date;
  method: string;
  path: string;
  status: number;
  raw: string;
};

type DailySummary = {
  date: string;
  total: number;
  byMethod: Record<string, number>;
  status2xx: number;
  status3xx: number;
  status4xx: number;
  status5xx: number;
};

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function toIsoDay(d: Date): string {
  return d.toISOString().slice(0, 10);
}

function parseApacheTimestamp(raw: string): Date | null {
  // Example: 10/Oct/2000:13:55:36 -0700
  const m = raw.match(
    /^(\d{1,2})\/([A-Za-z]{3})\/(\d{4}):(\d{2}):(\d{2}):(\d{2})\s+([+-]\d{4})$/
  );
  if (!m) return null;

  const [, dd, mon, yyyy, hh, mm, ss, tz] = m;
  const monthMap: Record<string, string> = {
    Jan: "01",
    Feb: "02",
    Mar: "03",
    Apr: "04",
    May: "05",
    Jun: "06",
    Jul: "07",
    Aug: "08",
    Sep: "09",
    Oct: "10",
    Nov: "11",
    Dec: "12",
  };

  const month = monthMap[mon];
  if (!month) return null;

  const iso = `${yyyy}-${month}-${dd.padStart(2, "0")}T${hh}:${mm}:${ss}${tz.slice(
    0,
    3
  )}:${tz.slice(3)}`;
  const d = new Date(iso);
  return Number.isNaN(d.getTime()) ? null : d;
}

function parseAccessLogLine(line: string): RequestLog | null {
  // Common/combined log format fragment:
  // ... [10/Oct/2000:13:55:36 -0700] "GET /path HTTP/1.1" 200 ...
  const requestMatch = line.match(/"([A-Z]+)\s+([^"\s]+)(?:\s+HTTP\/[0-9.]+)?"/);
  const statusMatch = line.match(/"\s+(\d{3})\b/);
  const tsMatch = line.match(/\[([^\]]+)\]/);

  if (!requestMatch || !statusMatch) return null;

  const method = requestMatch[1];
  const path = requestMatch[2];
  const status = Number(statusMatch[1]);
  const ts = tsMatch ? parseApacheTimestamp(tsMatch[1]) : null;

  return {
    timestamp: ts ?? new Date(),
    method,
    path,
    status,
    raw: line,
  };
}

function createDailySummary(date: string): DailySummary {
  return {
    date,
    total: 0,
    byMethod: {},
    status2xx: 0,
    status3xx: 0,
    status4xx: 0,
    status5xx: 0,
  };
}

function updateDailySummary(summary: DailySummary, req: RequestLog): DailySummary {
  summary.total += 1;
  summary.byMethod[req.method] = (summary.byMethod[req.method] ?? 0) + 1;

  if (req.status >= 200 && req.status < 300) summary.status2xx += 1;
  else if (req.status >= 300 && req.status < 400) summary.status3xx += 1;
  else if (req.status >= 400 && req.status < 500) summary.status4xx += 1;
  else if (req.status >= 500 && req.status < 600) summary.status5xx += 1;

  return summary;
}

function summaryToCsvRow(summary: DailySummary): string {
  const get = summary.byMethod["GET"] ?? 0;
  const post = summary.byMethod["POST"] ?? 0;
  const put = summary.byMethod["PUT"] ?? 0;
  const patch = summary.byMethod["PATCH"] ?? 0;
  const del = summary.byMethod["DELETE"] ?? 0;
  return [
    summary.date,
    summary.total,
    get,
    post,
    put,
    patch,
    del,
    summary.status2xx,
    summary.status3xx,
    summary.status4xx,
    summary.status5xx,
  ].join(",");
}

async function appendSummaryRow(reportCsvPath: string, summary: DailySummary): Promise<void> {
  const header =
    "date,total,GET,POST,PUT,PATCH,DELETE,status2xx,status3xx,status4xx,status5xx";
  let existing = "";
  try {
    existing = await readFile(reportCsvPath);
  } catch {
    existing = "";
  }

  const trimmed = existing.trim();
  const lines: string[] = [];

  if (!trimmed) {
    lines.push(header);
  } else {
    lines.push(trimmed);
    if (!trimmed.split(/\r?\n/)[0].startsWith("date,total")) {
      lines.unshift(header);
    }
  }

  lines.push(summaryToCsvRow(summary));
  await writeFile(reportCsvPath, lines.join("\n") + "\n");
}

async function* tailFileLines(path: string, intervalMs = 1000): AsyncIterable<string> {
  let lastLineCount = 0;

  while (true) {
    let content = "";
    try {
      content = await readFile(path);
    } catch {
      content = "";
    }

    const lines = content.split(/\r?\n/).filter((l) => l.length > 0);

    if (lines.length > lastLineCount) {
      for (let i = lastLineCount; i < lines.length; i++) {
        yield lines[i];
      }
      lastLineCount = lines.length;
    } else if (lines.length < lastLineCount) {
      // file rotated/truncated
      lastLineCount = 0;
      for (const line of lines) {
        yield line;
      }
      lastLineCount = lines.length;
    }

    await sleep(intervalMs);
  }
}

export async function tailLogAndAppendDailySummary(
  accessLogPath: string,
  reportCsvPath: string,
  pollIntervalMs = 1000
): Promise<void> {
  let currentDay = "";
  let summary: DailySummary | null = null;

  for await (const line of tailFileLines(accessLogPath, pollIntervalMs)) {
    const req = parseAccessLogLine(line);
    if (!req) continue;

    const day = toIsoDay(req.timestamp);

    if (!summary) {
      currentDay = day;
      summary = createDailySummary(day);
    }

    if (day !== currentDay) {
      await appendSummaryRow(reportCsvPath, summary);
      currentDay = day;
      summary = createDailySummary(day);
    }

    updateDailySummary(summary, req);
  }
}

{
  "name": "image-thumbnail-to-s3",
  "nodes": {
    "imageUploads": {
      "type": "producer",
      "source": "filesystem-watch",
      "config": {
        "path": "/uploads/images",
        "glob": "**/*.{jpg,jpeg,png,gif,webp}",
        "recursive": true
      }
    },
    "thumbnail": {
      "type": "derived",
      "deps": ["imageUploads"],
      "fn": "transformPayload",
      "config": {
        "template": {
          "operation": "resizeImage",
          "width": 256,
          "height": 256,
          "fit": "cover",
          "output": "thumbnail"
        }
      }
    },
    "uploadThumbnail": {
      "type": "effect",
      "deps": ["thumbnail"],
      "fn": "uploadToS3",
      "config": {
        "bucket": "image-thumbnails",
        "key": "thumbnails/{{filename}}-256x256.jpg"
      }
    }
  }
}

type ImageUploadEvent = {
  path: string;
  fileName?: string;
};

declare function watchFolder(folderPath: string): AsyncIterable<ImageUploadEvent>;
declare function readBinaryFile(path: string): Promise<Uint8Array>;
declare function resizeImage(
  input: Uint8Array,
  width: number,
  height: number
): Promise<Uint8Array>;
declare function uploadToS3(
  bucket: string,
  key: string,
  body: Uint8Array,
  contentType?: string
): Promise<void>;

function isImageFile(filePath: string): boolean {
  return /\.(png|jpe?g|webp|gif)$/i.test(filePath);
}

function toThumbnailKey(filePath: string): string {
  const normalized = filePath.replace(/\\/g, "/");
  const parts = normalized.split("/");
  const file = parts.pop() ?? "image";
  const base = file.replace(/\.[^.]+$/, "");
  const dir = parts.join("/");
  return `${dir ? `${dir}/` : ""}${base}_256x256.jpg`;
}

async function processUpload(event: ImageUploadEvent, bucket: string): Promise<void> {
  if (!isImageFile(event.path)) return;

  const imageBytes = await readBinaryFile(event.path);
  const thumbnail = await resizeImage(imageBytes, 256, 256);
  const key = toThumbnailKey(event.path);

  await uploadToS3(bucket, key, thumbnail, "image/jpeg");
  await logToAudit({
    action: "thumbnail_uploaded",
    sourcePath: event.path,
    s3Bucket: bucket,
    s3Key: key,
    size: "256x256",
    at: new Date().toISOString(),
  });
}

export async function watchImageUploadsAndCreateThumbnails(
  folderPath: string,
  bucket: string
): Promise<void> {
  for await (const event of watchFolder(folderPath)) {
    try {
      await processUpload(event, bucket);
    } catch (error) {
      await logToAudit({
        action: "thumbnail_upload_failed",
        sourcePath: event.path,
        error: error instanceof Error ? error.message : String(error),
        at: new Date().toISOString(),
      });
    }
  }
}

{
  "name": "dns-resolver-cache",
  "nodes": {
    "dnsQuery": {
      "type": "producer",
      "source": "http-server",
      "config": {
        "path": "/dns-query",
        "port": 53
      }
    },
    "domain": {
      "type": "derived",
      "deps": [
        "dnsQuery"
      ],
      "fn": "regexExtractFields",
      "config": {
        "patterns": {
          "domain": "([a-zA-Z0-9.-]+\\.[a-zA-Z]{2,})"
        }
      }
    },
    "authoritativeLookup": {
      "type": "derived",
      "deps": [
        "domain"
      ],
      "fn": "lookupCustomer",
      "config": {
        "source": "authoritative-nameserver"
      }
    },
    "cachedResult": {
      "type": "derived",
      "deps": [
        "authoritativeLookup"
      ],
      "fn": "cache",
      "config": {
        "ttlMs": 300000
      }
    },
    "response": {
      "type": "effect",
      "deps": [
        "cachedResult"
      ],
      "fn": "sendResponse"
    }
  }
}

type CacheEntry = {
  ip: string;
  expiresAt: number;
};

type AuthoritativeResponse = {
  ip: string;
  ttl?: number; // seconds
};

const dnsCache = new Map<string, CacheEntry>();
const DEFAULT_TTL_SECONDS = 300;

function nowMs(): number {
  return Date.now();
}

function normalizeDomain(domain: string): string {
  return domain.trim().toLowerCase();
}

function isCacheValid(entry: CacheEntry | undefined): entry is CacheEntry {
  return !!entry && entry.expiresAt > nowMs();
}

async function lookupAuthoritativeNameserver(domain: string): Promise<{ ip: string; ttlSeconds: number }> {
  const response = (await fetchFromApi(
    `https://authoritative-ns.example/resolve?domain=${encodeURIComponent(domain)}`
  )) as AuthoritativeResponse;

  if (!response?.ip) {
    throw new Error(`Authoritative lookup failed for domain: ${domain}`);
  }

  const ttlSeconds =
    typeof response.ttl === "number" && response.ttl > 0 ? response.ttl : DEFAULT_TTL_SECONDS;

  return { ip: response.ip, ttlSeconds };
}

function cacheResult(domain: string, ip: string, ttlSeconds: number): void {
  dnsCache.set(domain, {
    ip,
    expiresAt: nowMs() + ttlSeconds * 1000,
  });
}

export async function resolveDnsQuery(domainInput: string): Promise<string> {
  const domain = normalizeDomain(domainInput);
  if (!domain) throw new Error("Invalid domain");

  const cached = dnsCache.get(domain);
  if (isCacheValid(cached)) {
    return cached.ip;
  }

  const { ip, ttlSeconds } = await lookupAuthoritativeNameserver(domain);
  cacheResult(domain, ip, ttlSeconds);
  return ip;
}

export async function handleDnsQuery(query: { domain: string }): Promise<{ domain: string; ip: string }> {
  const ip = await resolveDnsQuery(query.domain);
  return { domain: normalizeDomain(query.domain), ip };
}

export function evictExpiredDnsCacheEntries(): void {
  const t = nowMs();
  for (const [domain, entry] of dnsCache.entries()) {
    if (entry.expiresAt <= t) dnsCache.delete(domain);
  }
}

{
  "name": "markdown-watch-render-deploy",
  "nodes": {
    "markdown_changes": {
      "type": "producer",
      "source": "filesystem-watch",
      "config": {
        "path": "/content",
        "glob": "**/*.md",
        "recursive": true
      }
    },
    "rendered_html": {
      "type": "derived",
      "deps": [
        "markdown_changes"
      ],
      "fn": "transformPayload",
      "config": {
        "template": "markdown-to-html",
        "syntaxHighlighting": true
      }
    },
    "deploy_pages": {
      "type": "effect",
      "deps": [
        "rendered_html"
      ],
      "fn": "uploadToS3",
      "config": {
        "bucket": "static-hosting-bucket",
        "key": "{filePath}.html"
      }
    }
  }
}

type ChangeEvent = {
  path?: string;
  filePath?: string;
  type?: "changed" | "created" | "deleted";
};

type DeployConfig = {
  watchUrl: string; // URL that emits file change events
  directory: string; // e.g. "/docs"
  bucketBaseUrl: string; // e.g. "https://static-host.example.com/my-bucket"
  intervalMs?: number;
};

export async function watchMarkdownAndDeploy(config: DeployConfig): Promise<void> {
  const stream = pollSource(config.watchUrl, config.intervalMs ?? 2000);

  for await (const rawEvent of stream) {
    const event = rawEvent as ChangeEvent;
    const changedPath = getChangedPath(event);
    if (!changedPath) continue;
    if (!isInDirectory(changedPath, config.directory)) continue;
    if (!isMarkdownFile(changedPath)) continue;
    if (event.type === "deleted") continue;

    await processAndDeployFile(changedPath, config.bucketBaseUrl);
  }
}

export async function processAndDeployFile(
  markdownPath: string,
  bucketBaseUrl: string
): Promise<void> {
  const markdown = await readFile(markdownPath);
  const html = renderMarkdownToHtml(markdown, markdownPath);
  const deployPath = toDeployPath(markdownPath);

  await fetchFromApi(joinUrl(bucketBaseUrl, deployPath), {
    method: "PUT",
    headers: { "Content-Type": "text/html; charset=utf-8" },
    body: html,
  });

  await logToAudit({
    action: "deploy_markdown_page",
    source: markdownPath,
    destination: deployPath,
    timestamp: new Date().toISOString(),
  });
}

function getChangedPath(event: ChangeEvent): string | null {
  return event.path ?? event.filePath ?? null;
}

function isInDirectory(filePath: string, directory: string): boolean {
  const dir = normalizePath(directory).replace(/\/+$/, "");
  const file = normalizePath(filePath);
  return file === dir || file.startsWith(dir + "/");
}

function isMarkdownFile(path: string): boolean {
  return /\.md$/i.test(path);
}

function toDeployPath(markdownPath: string): string {
  const normalized = normalizePath(markdownPath);
  return normalized.replace(/\.md$/i, ".html").replace(/^\/+/, "");
}

function normalizePath(p: string): string {
  return p.replace(/\\/g, "/");
}

function joinUrl(base: string, path: string): string {
  return `${base.replace(/\/+$/, "")}/${path.replace(/^\/+/, "")}`;
}

export function renderMarkdownToHtml(markdown: string, titleFromPath?: string): string {
  const body = renderBlocks(markdown);
  const title = titleFromPath ? deriveTitle(titleFromPath) : "Document";

  return `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${escapeHtml(title)}</title>
  <style>
    :root { color-scheme: light dark; }
    body { font-family: Inter, system-ui, -apple-system, Segoe UI, Roboto, sans-serif; max-width: 860px; margin: 2rem auto; padding: 0 1rem; line-height: 1.65; }
    pre { background: #0f172a; color: #e2e8f0; padding: 1rem; border-radius: 10px; overflow: auto; }
    code { font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; }
    p code, li code { background: rgba(127,127,127,.15); padding: .1rem .35rem; border-radius: 6px; }
