function deriveTitle(path: string): string {
  const file = normalizePath(path).split("/").pop() ?? "Document";
  const base = file.replace(/\.md$/i, "");
  return base.replace(/[-_]/g, " ").replace(/\b\w/g, (m) => m.toUpperCase());
}

function renderBlocks(markdown: string): string {
  const lines = markdown.replace(/\r\n/g, "\n").split("\n");
  const out: string[] = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    const fenceMatch = line.match(/^```(\w+)?\s*$/);
    if (fenceMatch) {
      const lang = (fenceMatch[1] || "").toLowerCase();
      i++;
      const codeLines: string[] = [];
      while (i < lines.length && !/^```/.test(lines[i])) {
        codeLines.push(lines[i]);
        i++;
      }
      if (i < lines.length && /^```/.test(lines[i])) i++;
      out.push(
        `<pre><code class="language-${escapeHtml(lang)}">${highlightCode(
          codeLines.join("\n"),
          lang
        )}</code></pre>`
      );
      continue;
    }

    const headingMatch = line.match(/^(#{1,6})\s+(.*)$/);
    if (headingMatch) {
      const level = headingMatch[1].length;
      out.push(`<h${level}>${renderInline(headingMatch[2])}</h${level}>`);
      i++;
      continue;
    }

    if (/^\s*[-*]\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*[-*]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\s*[-*]\s+/, ""));
        i++;
      }
      out.push(`<ul>${items.map((it) => `<li>${renderInline(it)}</li>`).join("")}</ul>`);
      continue;
    }

    if (/^\s*\d+\.\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\s*\d+\.\s+/, ""));
        i++;
      }
      out.push(`<ol>${items.map((it) => `<li>${renderInline(it)}</li>`).join("")}</ol>`);
      continue;
    }

    if (line.trim() === "") {
      i++;
      continue;
    }

    const para: string[] = [line];
    i++;
    while (
      i < lines.length &&
      lines[i].trim() !== "" &&
      !/^(#{1,6})\s+/.test(lines[i]) &&
      !/^```/.test(lines[i]) &&
      !/^\s*[-*]\s+/.test(lines[i]) &&
      !/^\s*\d+\.\s+/.test(lines[i])
    ) {
      para.push(lines[i]);
      i++;
    }
    out.push(`<p>${renderInline(para.join(" "))}</p>`);
  }

  return out.join("\n");
}

function renderInline(text: string): string {
  let s = escapeHtml(text);

  s = s.replace(/`([^`]+)`/g, (_m, g1) => `<code>${g1}</code>`);
  s = s.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
  s = s.replace(/\*([^*]+)\*/g, "<em>$1</em>");
  s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');

  return s;
}

function highlightCode(code: string, language: string): string {
  const escaped = escapeHtml(code);

  if (["ts", "tsx", "js", "jsx", "typescript", "javascript"].includes(language)) {
    return escaped
      .replace(
        /\b(const|let|var|function|return|if|else|for|while|async|await|import|from|export|class|new|try|catch|throw|extends|implements|interface|type)\b/g,
        '<span class="tok-keyword">$1</span>'
      )
      .replace(/("[^"]*"|'[^']*'|`[^`]*`)/g, '<span class="tok-string">$1</span>')
      .replace(/\b(\d+(?:\.\d+)?)\b/g, '<span class="tok-number">$1</span>')
      .replace(/(\/\/[^\n]*|\/\*[\s\S]*?\*\/)/g, '<span class="tok-comment">$1</span>')
      .replace(/\b([A-Za-z_$][A-Za-z0-9_$]*)(?=\()/g, '<span class="tok-function">$1</span>');
  }

  if (["py", "python"].includes(language)) {
    return escaped
      .replace(
        /\b(def|class|return|if|elif|else|for|while|import|from|as|try|except|raise|with|async|await|lambda|pass|yield|True|False|None)\b/g,
        '<span class="tok-keyword">$1</span>'
      )
      .replace(/("[^"]*"|'[^']*')/g, '<span class="tok-string">$1</span>')
      .replace(/\b(\d+(?:\.\d+)?)\b/g, '<span class="tok-number">$1</span>')
      .replace(/(#.*)$/gm, '<span class="tok-comment">$1</span>');
  }

  return escaped;
}

function escapeHtml(input: string): string {
  return input
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

