type EmailMessage = {
  id?: string;
  from?: string;
  sender?: string;
  subject?: string;
  body?: string;
  text?: string;
  date?: string;
  [key: string]: any;
};

const otherBySender = new Map<string, number>();

function getSender(email: EmailMessage): string {
  return (email.from || email.sender || "unknown").toLowerCase().trim();
}

function getEmailText(email: EmailMessage): string {
  const subject = email.subject ?? "";
  const body = email.body ?? email.text ?? "";
  return `${subject}\n\n${body}`.trim();
}

function getWeekKey(dateInput?: string): string {
  const d = dateInput ? new Date(dateInput) : new Date();
  const date = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
  const dayNum = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  const weekNo = Math.ceil((((date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
  return `${date.getUTCFullYear()}-W${String(weekNo).padStart(2, "0")}`;
}

async function classifyEmail(email: EmailMessage): Promise<"urgent" | "newsletter" | "other"> {
  const raw = await llmClassify(getEmailText(email), ["urgent", "newsletter", "other"]);
  const label = String(raw || "").toLowerCase().trim();
  if (label === "urgent" || label === "newsletter" || label === "other") return label;
  return "other";
}

async function routeUrgent(email: EmailMessage): Promise<void> {
  await writeToDatabase("priority_list", {
    emailId: email.id ?? null,
    from: getSender(email),
    subject: email.subject ?? "",
    body: email.body ?? email.text ?? "",
    receivedAt: email.date ?? new Date().toISOString(),
    priority: "high",
  });
}

async function routeNewsletter(email: EmailMessage): Promise<void> {
  await writeToDatabase("weekly_digest", {
    week: getWeekKey(email.date),
    emailId: email.id ?? null,
    from: getSender(email),
    subject: email.subject ?? "",
    snippet: (email.body ?? email.text ?? "").slice(0, 280),
    receivedAt: email.date ?? new Date().toISOString(),
  });
}

async function countOtherBySender(email: EmailMessage): Promise<void> {
  const sender = getSender(email);
  const nextCount = (otherBySender.get(sender) ?? 0) + 1;
  otherBySender.set(sender, nextCount);

  await writeToDatabase("other_email_sender_counts", {
    sender,
    count: nextCount,
    updatedAt: new Date().toISOString(),
  });
}

async function processEmail(email: EmailMessage): Promise<void> {
  const category = await classifyEmail(email);

  if (category === "urgent") {
    await routeUrgent(email);
    return;
  }

  if (category === "newsletter") {
    await routeNewsletter(email);
    return;
  }

  await countOtherBySender(email);
}

async function watchInboxAndRoute(): Promise<void> {
  for await (const incoming of watchEmail({})) {
    await processEmail(incoming as EmailMessage);
  }
}

async function main(): Promise<void> {
  await watchInboxAndRoute();
}

