type TemperatureReading = {
  sensorId: string;
  valueCelsius: number;
  timestamp: string;
};

const IOT_GATEWAY_URL = "https://iot-gateway.local/sensors/temperature";
const DASHBOARD_API_URL = "https://dashboard.local/widgets/temperature";
const HVAC_API_URL = "https://building-control.local/hvac/adjust";
const TEMPERATURE_THRESHOLD_C = 28;

async function readTemperatureFromGateway(): Promise<TemperatureReading> {
  const data = await fetchFromApi(IOT_GATEWAY_URL);
  return {
    sensorId: data.sensorId ?? "temp-sensor-1",
    valueCelsius: Number(data.valueCelsius ?? data.temperature ?? 0),
    timestamp: data.timestamp ?? new Date().toISOString(),
  };
}

async function pushToTimeSeriesDatabase(reading: TemperatureReading): Promise<void> {
  await writeToDatabase("temperature_timeseries", reading);
}

async function updateDashboardWidget(reading: TemperatureReading): Promise<void> {
  await fetchFromApi(DASHBOARD_API_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      widgetId: "temperature-live",
      value: reading.valueCelsius,
      unit: "°C",
      timestamp: reading.timestamp,
      sensorId: reading.sensorId,
    }),
  });
}

async function checkThresholdAndAdjustHvac(
  reading: TemperatureReading,
  thresholdCelsius: number = TEMPERATURE_THRESHOLD_C
): Promise<void> {
  if (reading.valueCelsius <= thresholdCelsius) return;

  await fetchFromApi(HVAC_API_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      action: "increase_cooling",
      reason: "temperature_threshold_exceeded",
      currentTemperature: reading.valueCelsius,
      threshold: thresholdCelsius,
      sensorId: reading.sensorId,
      timestamp: reading.timestamp,
    }),
  });

  await logToAudit({
    type: "HVAC_ADJUSTMENT_TRIGGERED",
    sensorId: reading.sensorId,
    currentTemperature: reading.valueCelsius,
    threshold: thresholdCelsius,
    timestamp: reading.timestamp,
  });
}

export async function processTemperatureReading(): Promise<TemperatureReading> {
  const reading = await readTemperatureFromGateway();

  await Promise.all([
    pushToTimeSeriesDatabase(reading),
    updateDashboardWidget(reading),
    checkThresholdAndAdjustHvac(reading),
  ]);

  return reading;
}

