  quantity: number;
};

type Order = {
  id: string;
  customerEmail: string;
  customerName?: string;
  items: OrderItem[];
  totalAmount: number;
  currency: string;
  paymentMethodId: string;
};

async function reserveInventory(order: Order): Promise<any> {
  return fetchFromApi("https://warehouse.example.com/reservations", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      orderId: order.id,
      items: order.items,
    }),
  });
}

async function chargePayment(order: Order): Promise<any> {
  return fetchFromApi("https://payments.example.com/charges", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      orderId: order.id,
      paymentMethodId: order.paymentMethodId,
