type BuildCompleteEvent = {
  pipelineId: string;
  project: string;
  environment: string;
  imageName: string;
  imageTag: string;
  registryApiUrl: string;
  registryNamespace?: string;
  registryToken?: string;
  gitopsManifestPath: string;
  slackChannel: string;
  gitApiUrl: string;
  gitRepo: string; // e.g. "org/repo"
  commitSha: string;
  releaseVersion: string; // e.g. "v1.2.3"
  gitToken?: string;
};

export async function onBuildCompleted(event: BuildCompleteEvent): Promise<void> {
  const imageRef = buildImageRef(event);

  await Promise.all([
    pushDockerImage(event, imageRef),
    updateGitOpsManifest(event.gitopsManifestPath, imageRef),
    sendReleaseSlackNotification(event, imageRef),
    tagGitCommit(event),
  ]);
}

function buildImageRef(event: BuildCompleteEvent): string {
  const namespace = event.registryNamespace ? `${event.registryNamespace}/` : "";
  const registryHost = event.registryApiUrl.replace(/^https?:\/\//, "").replace(/\/+$/, "");
  return `${registryHost}/${namespace}${event.imageName}:${event.imageTag}`;
}

async function pushDockerImage(event: BuildCompleteEvent, imageRef: string): Promise<void> {
  await fetchFromApi(`${event.registryApiUrl.replace(/\/+$/, "")}/v1/images/push`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...(event.registryToken ? { Authorization: `Bearer ${event.registryToken}` } : {}),
    },
    body: JSON.stringify({
      image: imageRef,
      source: "ci-cd",
      pipelineId: event.pipelineId,
    }),
  });
}

async function updateGitOpsManifest(manifestPath: string, imageRef: string): Promise<void> {
  const current = await readFile(manifestPath);
  const updated = replaceImageInManifest(current, imageRef);
  await writeFile(manifestPath, updated);
}

function replaceImageInManifest(manifest: string, imageRef: string): string {
  const imageLineRegex = /^(\s*image:\s*)(["']?)([^"'\n]+)\2\s*$/m;
  if (imageLineRegex.test(manifest)) {
    return manifest.replace(imageLineRegex, `$1${imageRef}`);
  }
  return `${manifest.trimEnd()}\nimage: ${imageRef}\n`;
}

async function sendReleaseSlackNotification(event: BuildCompleteEvent, imageRef: string): Promise<void> {
  const message =
    `✅ Build complete for *${event.project}* (${event.environment})\n` +
    `• Pipeline: ${event.pipelineId}\n` +
    `• Image: \`${imageRef}\`\n` +
    `• Release: \`${event.releaseVersion}\`\n` +
    `• Commit: \`${event.commitSha.slice(0, 7)}\``;

  await sendSlackMessage(event.slackChannel, message);
}

async function tagGitCommit(event: BuildCompleteEvent): Promise<void> {
  const base = event.gitApiUrl.replace(/\/+$/, "");
  await fetchFromApi(`${base}/repos/${event.gitRepo}/git/refs`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...(event.gitToken ? { Authorization: `Bearer ${event.gitToken}` } : {}),
    },
    body: JSON.stringify({
      ref: `refs/tags/${event.releaseVersion}`,
      sha: event.commitSha,
    }),
  });
}

