type CalendarEvent = {
  title?: string;
  start_time?: string;
  location?: string;
};

function getTodayDateKey(): string {
  return new Date().toISOString().slice(0, 10);
}

async function fetchTodaysWeather(): Promise<string> {
  const weather = await fetchFromApi("https://api.weather.example.com/forecast/today");
  const summary =
    weather?.summary ||
    weather?.forecast ||
    (weather?.temperature ? `Temperature ${weather.temperature}°` : null);

  if (summary) return String(summary);
  return "Weather data is unavailable.";
}

async function fetchTodaysCalendarEvents(): Promise<CalendarEvent[]> {
  const date = getTodayDateKey();
  const sql = `
    SELECT title, start_time, location
    FROM calendar_events
    WHERE DATE(start_time) = '${date}'
    ORDER BY start_time ASC
  `;
  return queryDatabase(sql);
}

function formatCalendarEvents(events: CalendarEvent[]): string {
  if (!events.length) return "No events on your calendar today.";

  const lines = mapItems(events, (event) => {
    const time = event.start_time
      ? new Date(event.start_time).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })
      : "Time TBD";
    const title = event.title || "Untitled event";
    const location = event.location ? ` (${event.location})` : "";
    return `- ${time}: ${title}${location}`;
  });

  return `Today's events:\n${lines.join("\n")}`;
}

async function fetchCurrentTraffic(): Promise<string> {
  const traffic = await fetchFromApi("https://api.traffic.example.com/current");
  const summary =
    traffic?.summary ||
    traffic?.condition ||
    traffic?.status ||
    (typeof traffic === "string" ? traffic : null);

  if (summary) return String(summary);
  return "Traffic data is unavailable.";
}

function buildMorningBriefingMessage(weather: string, eventsText: string, traffic: string): string {
  return [
    "Good morning! Here's your briefing:",
    "",
    `Weather: ${weather}`,
    "",
    eventsText,
    "",
    `Traffic: ${traffic}`,
  ].join("\n");
}

export async function generateMorningBriefing(): Promise<string> {
  const [weather, events, traffic] = await Promise.all([
    fetchTodaysWeather(),
    fetchTodaysCalendarEvents(),
    fetchCurrentTraffic(),
  ]);

  const eventsText = formatCalendarEvents(events);
  return buildMorningBriefingMessage(weather, eventsText, traffic);
}

export async function main(): Promise<string> {
  return generateMorningBriefing();
}

