type LabResult = {
  testName: string;
  value: string | number;
  unit?: string;
  referenceRange?: string;
  status?: string;
  collectedAt?: string;
};

type Medication = {
  name: string;
  dose?: string;
  route?: string;
  frequency?: string;
  status?: string;
  startDate?: string;
  endDate?: string;
};

type Vital = {
  type: string;
  value: string | number;
  unit?: string;
  takenAt?: string;
};

type PreVisitSummary = {
  patientId: string;
  generatedAt: string;
  labs: LabResult[];
  medications: Medication[];
  vitals: Vital[];
  physicianSummary: string;
};

function asArray<T>(input: any): T[] {
  if (Array.isArray(input)) return input as T[];
  if (input == null) return [];
  return [input as T];
}

function sortByDateDesc<T>(items: T[], getDate: (item: T) => string | undefined): T[] {
  return [...items].sort((a, b) => {
    const da = new Date(getDate(a) ?? 0).getTime();
    const db = new Date(getDate(b) ?? 0).getTime();
    return db - da;
  });
}

function normalizeLabResults(raw: any): LabResult[] {
  const rows = asArray<any>(raw?.results ?? raw?.labs ?? raw);
  return rows.map((r) => ({
    testName: r.testName ?? r.name ?? r.test ?? "Unknown Test",
    value: r.value ?? r.result ?? "",
    unit: r.unit,
    referenceRange: r.referenceRange ?? r.refRange,
    status: r.status ?? r.flag,
    collectedAt: r.collectedAt ?? r.timestamp ?? r.date,
  }));
}

function normalizeMedications(raw: any): Medication[] {
  const rows = asArray<any>(raw?.medications ?? raw?.results ?? raw);
  return rows.map((m) => ({
    name: m.name ?? m.medicationName ?? "Unknown Medication",
    dose: m.dose ?? m.strength,
    route: m.route,
    frequency: m.frequency ?? m.sig,
    status: m.status ?? m.state,
    startDate: m.startDate,
    endDate: m.endDate,
  }));
}

function normalizeVitals(raw: any): Vital[] {
  const rows = asArray<any>(raw?.vitals ?? raw?.results ?? raw);
  return rows.map((v) => ({
    type: v.type ?? v.name ?? v.metric ?? "Unknown Vital",
    value: v.value ?? v.reading ?? "",
    unit: v.unit,
    takenAt: v.takenAt ?? v.timestamp ?? v.date,
  }));
}

async function fetchLabResultsFromLims(patientId: string): Promise<LabResult[]> {
  const data = await fetchFromApi(
    `https://lims.internal/api/patients/${encodeURIComponent(patientId)}/lab-results`
  );
  return sortByDateDesc(normalizeLabResults(data), (x) => x.collectedAt);
}

async function fetchCurrentMedicationsFromPharmacy(patientId: string): Promise<Medication[]> {
  const data = await fetchFromApi(
    `https://pharmacy.internal/api/patients/${encodeURIComponent(patientId)}/medications?status=current`
  );
  const meds = normalizeMedications(data);
  return meds.filter((m) => {
    const s = (m.status ?? "").toLowerCase();
    return s === "" || s.includes("active") || s.includes("current");
  });
}

async function fetchRecentVitalsFromNursingStation(patientId: string): Promise<Vital[]> {
  const data = await fetchFromApi(
    `https://nursing-station.internal/api/patients/${encodeURIComponent(patientId)}/vitals?window=72h`
  );
  return sortByDateDesc(normalizeVitals(data), (x) => x.takenAt).slice(0, 20);
}

function formatPhysicianSummary(patientId: string, labs: LabResult[], meds: Medication[], vitals: Vital[]): string {
  const abnormalLabs = labs.filter((l) => {
    const s = (l.status ?? "").toLowerCase();
    return s.includes("abnormal") || s.includes("critical") || s.includes("high") || s.includes("low");
  });

  const latestVitalsByType = Object.values(
    groupBy(vitals, "type")
  ).map((group) => sortByDateDesc(group, (v) => v.takenAt)[0]);

  const labText =
    labs.length === 0
      ? "No recent lab results."
      : labs
          .slice(0, 10)
          .map((l) => {
            const value = `${l.value}${l.unit ? ` ${l.unit}` : ""}`;
            const status = l.status ? ` (${l.status})` : "";
            return `- ${l.testName}: ${value}${status}`;
          })
          .join("\n");

  const abnormalLabText =
    abnormalLabs.length === 0
      ? "No flagged abnormal/critical labs."
      : abnormalLabs
          .slice(0, 10)
          .map((l) => `- ${l.testName}: ${l.value}${l.unit ? ` ${l.unit}` : ""}${l.status ? ` (${l.status})` : ""}`)
          .join("\n");

  const medText =
    meds.length === 0
      ? "No active medications found."
      : meds
          .map((m) => {
            const details = [m.dose, m.route, m.frequency].filter(Boolean).join(", ");
            return `- ${m.name}${details ? ` — ${details}` : ""}`;
          })
          .join("\n");

  const vitalText =
    latestVitalsByType.length === 0
      ? "No recent vitals."
      : latestVitalsByType
          .map((v) => `- ${v.type}: ${v.value}${v.unit ? ` ${v.unit}` : ""}${v.takenAt ? ` (at ${v.takenAt})` : ""}`)
          .join("\n");

  return [
    `Pre-Visit Summary for Patient ${patientId}`,
    `Generated: ${new Date().toISOString()}`,
    "",
    "Flagged Labs:",
    abnormalLabText,
    "",
    "Recent Labs:",
    labText,
    "",
    "Current Medications:",
    medText,
    "",
    "Latest Vitals:",
    vitalText,
  ].join("\n");
}

async function buildPreVisitSummary(patientId: string): Promise<PreVisitSummary> {
  const [labs, medications, vitals] = await Promise.all([
    fetchLabResultsFromLims(patientId),
    fetchCurrentMedicationsFromPharmacy(patientId),
    fetchRecentVitalsFromNursingStation(patientId),
  ]);

  const physicianSummary = formatPhysicianSummary(patientId, labs, medications, vitals);

  return {
    patientId,
    generatedAt: new Date().toISOString(),
    labs,
    medications,
    vitals,
    physicianSummary,
  };
}

