type Source = 'twitter' | 'reddit' | 'hackernews';
type Sentiment = 'positive' | 'neutral' | 'negative';

interface Mention {
  source: Source;
  text: string;
  url?: string;
  createdAt?: string;
}

interface MentionWithSentiment extends Mention {
  sentiment: Sentiment;
  score: number;
}

interface SentimentBreakdown {
  positive: number;
  neutral: number;
  negative: number;
}

interface SourceAttribution {
  mentions: number;
  averageScore: number;
  sentimentCounts: SentimentBreakdown;
}

interface UnifiedSentimentReport {
  brand: string;
  totalMentions: number;
  unifiedSentimentScore: number;
  sentimentCounts: SentimentBreakdown;
  sourceAttribution: Record<Source, SourceAttribution>;
  mentions: MentionWithSentiment[];
}

function normalizeArray(payload: any, keys: string[]): any[] {
  if (Array.isArray(payload)) return payload;
  for (const key of keys) {
    if (Array.isArray(payload?.[key])) return payload[key];
  }
  return [];
}

function scoreFromSentiment(sentiment: string): number {
  if (sentiment === 'positive') return 1;
  if (sentiment === 'negative') return -1;
  return 0;
}

async function fetchTwitterMentions(brand: string): Promise<Mention[]> {
  const url = `https://api.twitter.com/2/tweets/search/recent?query=${encodeURIComponent(brand)}`;
  const data = await fetchFromApi(url);
  const items = normalizeArray(data, ['data', 'tweets', 'results']);
  return items
    .map((item: any) => ({
      source: 'twitter' as const,
      text: String(item?.text ?? '').trim(),
      url: item?.id ? `https://twitter.com/i/web/status/${item.id}` : item?.url,
      createdAt: item?.created_at ?? item?.createdAt,
    }))
    .filter((m: Mention) => m.text.length > 0);
}

async function fetchRedditMentions(brand: string): Promise<Mention[]> {
  const url = `https://www.reddit.com/search.json?q=${encodeURIComponent(brand)}&sort=new`;
  const data = await fetchFromApi(url);
  const children = normalizeArray(data?.data, ['children']);
  return children
    .map((child: any) => child?.data ?? child)
    .map((post: any) => {
      const title = String(post?.title ?? '').trim();
      const body = String(post?.selftext ?? post?.body ?? '').trim();
      const text = [title, body].filter(Boolean).join(' — ');
      return {
        source: 'reddit' as const,
        text,
        url: post?.permalink ? `https://reddit.com${post.permalink}` : post?.url,
        createdAt: post?.created_utc
          ? new Date(post.created_utc * 1000).toISOString()
          : post?.createdAt,
      };
    })
    .filter((m: Mention) => m.text.length > 0);
}

async function fetchHackerNewsMentions(brand: string): Promise<Mention[]> {
  const url = `https://hn.algolia.com/api/v1/search?query=${encodeURIComponent(brand)}`;
  const data = await fetchFromApi(url);
  const hits = normalizeArray(data, ['hits', 'data', 'results']);
  return hits
    .map((hit: any) => {
      const title = String(hit?.title ?? '').trim();
      const storyText = String(hit?.story_text ?? hit?.comment_text ?? '').trim();
      const text = [title, storyText].filter(Boolean).join(' — ');
      return {
        source: 'hackernews' as const,
        text,
        url: hit?.url ?? hit?.story_url,
        createdAt: hit?.created_at ?? hit?.createdAt,
      };
    })
    .filter((m: Mention) => m.text.length > 0);
}

async function classifyMention(mention: Mention): Promise<MentionWithSentiment> {
  const sentiment = (await llmClassify(mention.text, [
    'positive',
    'neutral',
    'negative',
  ])) as Sentiment;

  return {
    ...mention,
    sentiment,
    score: scoreFromSentiment(sentiment),
  };
}

function emptyBreakdown(): SentimentBreakdown {
  return { positive: 0, neutral: 0, negative: 0 };
}

function getAttribution(mentions: MentionWithSentiment[]): Record<Source, SourceAttribution> {
  const grouped = groupBy(mentions, 'source') as Record<Source, MentionWithSentiment[]>;
  const sources: Source[] = ['twitter', 'reddit', 'hackernews'];

  const result = {} as Record<Source, SourceAttribution>;

  for (const source of sources) {
    const items = grouped[source] ?? [];
    const totalScore = aggregate(items, (acc: number, item) => acc + item.score, 0);
    const sentimentCounts = items.reduce(
      (acc, item) => {
        acc[item.sentiment] += 1;
        return acc;
      },
      emptyBreakdown()
    );

    result[source] = {
      mentions: items.length,
      averageScore: items.length ? totalScore / items.length : 0,
      sentimentCounts,
    };
  }

  return result;
}

export async function collectBrandMentionsSentiment(brand: string): Promise<UnifiedSentimentReport> {
  const [twitterMentions, redditMentions, hackerNewsMentions] = await Promise.all([
    fetchTwitterMentions(brand),
    fetchRedditMentions(brand),
    fetchHackerNewsMentions(brand),
  ]);

  const allMentions = [...twitterMentions, ...redditMentions, ...hackerNewsMentions];
  const mentions = await Promise.all(allMentions.map(classifyMention));

  const totalMentions = mentions.length;
  const totalScore = aggregate(mentions, (acc: number, item) => acc + item.score, 0);
  const sentimentCounts = mentions.reduce(
    (acc, item) => {
      acc[item.sentiment] += 1;
      return acc;
    },
    emptyBreakdown()
  );

  return {
    brand,
    totalMentions,
    unifiedSentimentScore: totalMentions ? totalScore / totalMentions : 0,
    sentimentCounts,
    sourceAttribution: getAttribution(mentions),
    mentions,
  };
}

