type MerchantRiskCategory = 'low' | 'medium' | 'high' | 'critical' | 'unknown';

interface CreditCardTransaction {
  id: string;
  cardId: string;
  merchantId: string;
  ipAddress: string;
  amount: number;
  currency: string;
  timestamp: string;
  billingCountry?: string;
}

interface FraudSignals {
  ipRiskScore: number;
  velocityRiskScore: number;
  merchantRiskScore: number;
}

interface FraudRiskResult {
  transactionId: string;
  riskScore: number;
  riskLevel: 'low' | 'medium' | 'high' | 'critical';
  signals: FraudSignals;
}

export async function scoreTransactionFraudRisk(
  tx: CreditCardTransaction
): Promise<FraudRiskResult> {
  const [ipRiskScore, velocityRiskScore, merchantRiskScore] = await Promise.all([
    getIpGeolocationRisk(tx.ipAddress, tx.billingCountry),
    getCardVelocityRisk(tx.cardId, tx.timestamp),
    getMerchantRisk(tx.merchantId),
  ]);

  const riskScore = clamp(
    Math.round(ipRiskScore * 0.4 + velocityRiskScore * 0.35 + merchantRiskScore * 0.25),
    0,
    100
  );

  return {
    transactionId: tx.id,
    riskScore,
    riskLevel: toRiskLevel(riskScore),
    signals: {
      ipRiskScore,
      velocityRiskScore,
      merchantRiskScore,
    },
  };
}

export async function scoreBatchFraudRisk(
  transactions: CreditCardTransaction[]
): Promise<FraudRiskResult[]> {
  return Promise.all(transactions.map(scoreTransactionFraudRisk));
}

async function getIpGeolocationRisk(ipAddress: string, billingCountry?: string): Promise<number> {
  const geo = await fetchFromApi(`https://geo.example.com/lookup?ip=${encodeURIComponent(ipAddress)}`);

  let score = 0;

  if (geo?.isAnonymousProxy || geo?.proxy || geo?.vpn || geo?.tor) score += 35;
  if (geo?.isHosting || geo?.isDatacenter) score += 20;

  const countryCode = String(geo?.countryCode || geo?.country || '').toUpperCase();
  const billing = String(billingCountry || '').toUpperCase();

  if (billing && countryCode && billing !== countryCode) score += 20;

  const highRiskCountries = new Set(['NG', 'PK', 'UA', 'RU', 'VE', 'ID']);
  if (countryCode && highRiskCountries.has(countryCode)) score += 20;

  if (typeof geo?.riskScore === 'number') {
    score += clamp(geo.riskScore * 0.25, 0, 25);
  }

  return clamp(Math.round(score), 0, 100);
}

async function getCardVelocityRisk(cardId: string, txTimestamp: string): Promise<number> {
  const safeCardId = escapeSql(cardId);

  const rows = await queryDatabase(`
    SELECT amount, merchant_id, status, created_at
    FROM transactions
    WHERE card_id = '${safeCardId}'
      AND created_at >= NOW() - INTERVAL '24 HOURS'
  `);

  const now = new Date(txTimestamp);
  const oneHourMs = 60 * 60 * 1000;

  let count1h = 0;
  let count24h = 0;
  let sum1h = 0;
  let maxAmount = 0;
  let declines1h = 0;
  const merchants24h = new Set<string>();

  for (const row of rows) {
    const createdAt = new Date(row.created_at);
    const ageMs = now.getTime() - createdAt.getTime();

    if (ageMs < 0 || ageMs > 24 * oneHourMs) continue;

    count24h += 1;
    merchants24h.add(String(row.merchant_id));

    const amount = Number(row.amount || 0);
    if (amount > maxAmount) maxAmount = amount;

    if (ageMs <= oneHourMs) {
      count1h += 1;
      sum1h += amount;
      if (String(row.status || '').toLowerCase() === 'declined') declines1h += 1;
    }
  }

  let score = 0;

  if (count1h >= 3) score += 15;
  if (count1h >= 6) score += 15;
  if (count24h >= 15) score += 15;
  if (sum1h >= 2000) score += 15;
  if (merchants24h.size >= 6) score += 15;
  if (declines1h >= 2) score += 15;
  if (maxAmount >= 5000) score += 10;

  return clamp(score, 0, 100);
}

async function getMerchantRisk(merchantId: string): Promise<number> {
  const safeMerchantId = escapeSql(merchantId);

  const rows = await queryDatabase(`
    SELECT risk_category, risk_score
    FROM merchants
    WHERE id = '${safeMerchantId}'
    LIMIT 1
  `);

  if (!rows.length) return 50;

  const row = rows[0];
  if (typeof row.risk_score === 'number') {
    return clamp(Math.round(row.risk_score), 0, 100);
  }

  const category = String(row.risk_category || 'unknown').toLowerCase() as MerchantRiskCategory;
  const map: Record<MerchantRiskCategory, number> = {
    low: 15,
    medium: 45,
    high: 75,
    critical: 90,
    unknown: 50,
  };

  return map[category] ?? 50;
}

function toRiskLevel(score: number): 'low' | 'medium' | 'high' | 'critical' {
  if (score >= 85) return 'critical';
  if (score >= 65) return 'high';
  if (score >= 40) return 'medium';
  return 'low';
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function escapeSql(value: string): string {
  return value.replace(/'/g, "''");
}

