```typescript
type MetricSnapshot = {
  cpuUtilization: number; // percent (0-100)
  memoryPressure: number; // percent (0-100)
  diskLatencyMs: number; // milliseconds
};

type HealthPayload = MetricSnapshot & {
  healthIndex: number; // 0-100, higher is healthier
  timestamp: string;
};

function clamp(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

function toPercent(value: number): number {
  if (!Number.isFinite(value)) return 0;
  return value <= 1 ? value * 100 : value;
}

function toNumber(input: any): number {
  if (typeof input === "number") return input;
  if (typeof input === "string") return Number(input);
  return Number.NaN;
}

function extractCpuUtilization(event: any): number {
  const candidates = [
    event?.cpuUtilization,
    event?.cpu_usage,
    event?.utilization,
    event?.value,
    event?.current,
  ];
  for (const c of candidates) {
    const n = toNumber(c);
    if (Number.isFinite(n)) return clamp(toPercent(n), 0, 100);
  }
  return Number.NaN;
}

function extractMemoryPressure(event: any): number {
  const candidates = [
    event?.memoryPressure,
    event?.pressure,
    event?.memory_pressure,
    event?.value,
    event?.current,
  ];
  for (const c of candidates) {
    const n = toNumber(c);
    if (Number.isFinite(n)) return clamp(toPercent(n), 0, 100);
  }
  return Number.NaN;
}

function extractDiskLatencyMs(event: any): number {
  const candidates = [
    event?.diskLatencyMs,
    event?.ioLatencyMs,
    event?.latencyMs,
    event?.latency,
    event?.value,
    event?.current,
  ];
  for (const c of candidates) {
    const n = toNumber(c);
    if (Number.isFinite(n)) return clamp(n, 0, 10_000);
  }
  return Number.NaN;
}

function scoreCpu(cpuUtilization: number): number {
  return clamp(100 - cpuUtilization, 0, 100);
}

function scoreMemory(memoryPressure: number): number {
  return clamp(100 - memoryPressure, 0, 100);
}

function scoreDiskLatency(diskLatencyMs: number): number {
  const good = 5;
  const bad = 200;
  const normalized = (diskLatencyMs - good) / (bad - good);
  return clamp(100 - normalized * 100, 0, 100);
}

function computeHealthIndex(snapshot: MetricSnapshot): number {
  const cpuScore = scoreCpu(snapshot.cpuUtilization);
  const memScore = scoreMemory(snapshot.memoryPressure);
  const diskScore = scoreDiskLatency(snapshot.diskLatencyMs);

  const weighted =
    cpuScore * 0.4 +
    memScore * 0.35 +
    diskScore * 0.25;

  return Math.round(clamp(weighted, 0, 100));
}

async function publishToOpsDashboard(payload: HealthPayload): Promise<void> {
  await Promise.all([
    fetchFromApi("https://ops-dashboard.internal/api/infrastructure-health", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    }),
    writeToDatabase("ops_dashboard_infra_health", payload),
  ]);
}

async function consumeMetricStream(
  stream: AsyncIterable<any>,
  extractor: (event: any) => number,
  onValue: (value: number) => Promise<void>
): Promise<void> {
  for await (const event of stream) {
    const value = extractor(event);
    if (Number.isFinite(value)) {
      await onValue(value);
    }
  }
}

export async function runInfrastructureHealthPublisher(): Promise<void> {
  const state: Partial<MetricSnapshot> = {};
  let publishQueue: Promise<void> = Promise.resolve();

  const onStateUpdate = async (): Promise<void> => {
    if (
      state.cpuUtilization == null ||
      state.memoryPressure == null ||
      state.diskLatencyMs == null
    ) {
      return;
    }

    const snapshot: MetricSnapshot = {
      cpuUtilization: state.cpuUtilization,
      memoryPressure: state.memoryPressure,
      diskLatencyMs: state.diskLatencyMs,
    };

    const payload: HealthPayload = {
      ...snapshot,
      healthIndex: computeHealthIndex(snapshot),
      timestamp: new Date().toISOString(),
    };

    publishQueue = publishQueue
      .then(() => publishToOpsDashboard(payload))
      .catch(async (error) => {
        await logToAudit({
          type: "infra-health-publish-error",
          error: String(error),
          payload,
          at: new Date().toISOString(),
        });
      });

    await publishQueue;
  };

  const cpuStream = pollSource(
    "https://compute-fleet.internal/metrics/cpu-utilization",
    5000
  );
  const memoryStream = pollSource(
    "https://memory-monitor.internal/metrics/memory-pressure",
    5000
  );
  const diskStream = pollSource(
    "https://storage-layer.internal/metrics/disk-io-latency",
    5000
  );

  await Promise.all([
    consumeMetricStream(cpuStream, extractCpuUtilization, async (value) => {
      state.cpuUtilization = value;
      await onStateUpdate();
    }),
    consumeMetricStream(memoryStream, extractMemoryPressure, async (value) => {
      state.memoryPressure = value;
      await onStateUpdate();
    }),
    consumeMetricStream(diskStream, extractDiskLatencyMs, async (value) => {
      state.diskLatencyMs = value;
      await onStateUpdate();
    }),
  ]);
}

export async function main(): Promise<void> {
  await runInfrastructureHealthPublisher();
}
