type PrimitiveType = "string" | "number" | "boolean" | "object" | "array" | "null";

type FieldRule =
  | PrimitiveType
  | {
      type: PrimitiveType;
      required?: boolean;
    };

type SchemaDefinition = Record<string, FieldRule>;

type ValidationError = {
  field: string;
  expected: PrimitiveType;
  actual: string;
  message: string;
};

type ValidationReport = {
  valid: boolean;
  errors: ValidationError[];
  checkedAt: string;
};

type ProcessedPayload = {
  validation: ValidationReport;
  data: any;
  processedAt: string;
};

function toCamelCase(key: string): string {
  return key
    .trim()
    .replace(/^[^a-zA-Z0-9]+|[^a-zA-Z0-9]+$/g, "")
    .replace(/[_\-\s]+(.)?/g, (_, ch: string) => (ch ? ch.toUpperCase() : ""))
    .replace(/^[A-Z]/, (m) => m.toLowerCase());
}

function detectType(value: any): PrimitiveType {
  if (value === null) return "null";
  if (Array.isArray(value)) return "array";
  const t = typeof value;
  if (t === "string" || t === "number" || t === "boolean" || t === "object") return t;
  return "null";
}

async function validateSchema(payload: any, schema: SchemaDefinition): Promise<ValidationReport> {
  const errors: ValidationError[] = [];

  for (const [field, rule] of Object.entries(schema)) {
    const expected = typeof rule === "string" ? rule : rule.type;
    const required = typeof rule === "string" ? true : rule.required !== false;
    const value = payload[field];

    if (value === undefined) {
      if (required) {
        errors.push({
          field,
          expected,
          actual: "undefined",
          message: `Missing required field: ${field}`,
        });
      }
      continue;
    }

    const actual = detectType(value);
    if (actual !== expected) {
      errors.push({
        field,
        expected,
        actual,
        message: `Invalid type for "${field}": expected ${expected}, got ${actual}`,
      });
    }
  }

  return {
    valid: errors.length === 0,
    errors,
    checkedAt: new Date().toISOString(),
  };
}

async function normalizeFieldNames(input: any): Promise<any> {
  if (Array.isArray(input)) {
    return Promise.all(input.map((item) => normalizeFieldNames(item)));
  }

  if (input !== null && typeof input === "object") {
    const entries = await Promise.all(
      Object.entries(input).map(async ([key, value]) => [toCamelCase(key), await normalizeFieldNames(value)] as const)
    );
    return Object.fromEntries(entries);
  }

  return input;
}

function parsePayload(payload: string | Record<string, any>): Record<string, any> {
  return typeof payload === "string" ? JSON.parse(payload) : payload;
}

async function processJsonPayload(
  payload: string | Record<string, any>,
  schema: SchemaDefinition,
  table = "processed_payloads"
): Promise<ProcessedPayload> {
  const parsed = parsePayload(payload);

  const [validation, data] = await Promise.all([validateSchema(parsed, schema), normalizeFieldNames(parsed)]);

  const merged: ProcessedPayload = {
    validation,
    data,
    processedAt: new Date().toISOString(),
  };

  await writeToDatabase(table, merged);
  return merged;
}

