type UploadedPhoto = {
  id: string;
  filename: string;
  mimeType: string;
  dataBase64: string;
  uploadedBy: string;
  uploadedAt: string;
};

type WatermarkedImage = {
  mimeType: string;
  dataBase64: string;
};

type TaggedMetadata = {
  tags: string[];
  confidence?: Record<string, number>;
};

type ContentLibraryItem = {
  id: string;
  filename: string;
  mimeType: string;
  imageBase64: string;
  tags: string[];
  uploadedBy: string;
  uploadedAt: string;
  processedAt: string;
};

async function classifyImage(photo: UploadedPhoto): Promise<TaggedMetadata> {
  const result = await fetchFromApi("https://api.example.com/image/classify", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      imageBase64: photo.dataBase64,
      mimeType: photo.mimeType,
    }),
  });

  return {
    tags: Array.isArray(result?.tags) ? result.tags : [],
    confidence: result?.confidence ?? {},
  };
}

async function applyWatermark(photo: UploadedPhoto): Promise<WatermarkedImage> {
  const result = await fetchFromApi("https://api.example.com/image/watermark", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      imageBase64: photo.dataBase64,
      mimeType: photo.mimeType,
      watermarkText: "© Content Library",
      position: "bottom-right",
    }),
  });

  return {
    mimeType: result?.mimeType ?? photo.mimeType,
    dataBase64: result?.imageBase64 ?? photo.dataBase64,
  };
}

function combineProcessedPhoto(
  photo: UploadedPhoto,
  metadata: TaggedMetadata,
  watermarked: WatermarkedImage
): ContentLibraryItem {
  return {
    id: photo.id,
    filename: photo.filename,
    mimeType: watermarked.mimeType,
    imageBase64: watermarked.dataBase64,
    tags: metadata.tags,
    uploadedBy: photo.uploadedBy,
    uploadedAt: photo.uploadedAt,
    processedAt: new Date().toISOString(),
  };
}

async function saveToContentLibrary(item: ContentLibraryItem): Promise<void> {
  await writeToDatabase("content_library", item);
}

export async function processUploadedPhoto(
  uploadedPhoto: UploadedPhoto
): Promise<ContentLibraryItem> {
  const [metadata, watermarkedImage] = await Promise.all([
    classifyImage(uploadedPhoto),
    applyWatermark(uploadedPhoto),
  ]);

  const libraryItem = combineProcessedPhoto(
    uploadedPhoto,
    metadata,
    watermarkedImage
  );

  await saveToContentLibrary(libraryItem);
  return libraryItem;
}

