type LoanApplication = {
  id: string;
  applicantId: string;
  fullName: string;
  email: string;
  requestedAmount: number;
};

type CreditResult = {
  score: number;
  raw?: any;
};

type EmploymentVerification = {
  verified: boolean;
  monthsVerified: number;
  employers: any[];
};

type UnderwritingDecision = {
  applicationId: string;
  applicantId: string;
  status: "approved" | "manual_review" | "denied";
  reason: string;
  creditScore: number;
  employmentVerified: boolean;
  requestedAmount: number;
  decidedAt: string;
};

export async function receiveLoanApplication(application: LoanApplication): Promise<UnderwritingDecision> {
  const [credit, employment] = await Promise.all([
    pullCreditScore(application.applicantId),
    verifyEmploymentHistory(application.applicantId),
  ]);

  const decision = makeUnderwritingDecision(application, credit, employment);

  await Promise.all([
    writeToDatabase("underwriting_decisions", decision),
    notifyApplicant(application, decision),
    logToAudit({
      event: "loan_underwriting_completed",
      applicationId: application.id,
      applicantId: application.applicantId,
      decision: decision.status,
      creditScore: decision.creditScore,
      employmentVerified: decision.employmentVerified,
      timestamp: decision.decidedAt,
    }),
  ]);

  return decision;
}

async function pullCreditScore(applicantId: string): Promise<CreditResult> {
  const data = await fetchFromApi(`https://credit-bureau.example.com/scores/${encodeURIComponent(applicantId)}`);
  return {
    score: Number(data.score ?? 0),
    raw: data,
  };
}

async function verifyEmploymentHistory(applicantId: string): Promise<EmploymentVerification> {
  const safeApplicantId = applicantId.replace(/'/g, "''");
  const rows = await queryDatabase(
    `SELECT employer, start_date, end_date, is_current
     FROM employment_history
     WHERE applicant_id = '${safeApplicantId}'
     ORDER BY start_date DESC`
  );

  const now = new Date();
  const monthsVerified = rows.reduce((total, row) => {
    const start = new Date(row.start_date);
    const end = row.is_current ? now : new Date(row.end_date);
    const months = Math.max(
      0,
      (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth())
    );
    return total + months;
  }, 0);

  const verified = rows.length > 0 && monthsVerified >= 12;

  return {
    verified,
    monthsVerified,
    employers: rows,
  };
}

function makeUnderwritingDecision(
  application: LoanApplication,
  credit: CreditResult,
  employment: EmploymentVerification
): UnderwritingDecision {
  let status: UnderwritingDecision["status"];
  let reason: string;

  if (credit.score >= 700 && employment.verified) {
    status = "approved";
    reason = "Strong credit score and verified employment history.";
  } else if (credit.score >= 620 && employment.verified) {
    status = "manual_review";
    reason = "Moderate credit score; routed for manual underwriting review.";
  } else {
    status = "denied";
    reason = !employment.verified
      ? "Employment history could not be sufficiently verified."
      : "Credit score below minimum underwriting threshold.";
  }

  return {
    applicationId: application.id,
    applicantId: application.applicantId,
    status,
    reason,
    creditScore: credit.score,
    employmentVerified: employment.verified,
    requestedAmount: application.requestedAmount,
    decidedAt: new Date().toISOString(),
  };
}

async function notifyApplicant(
  application: LoanApplication,
  decision: UnderwritingDecision
): Promise<void> {
  const subject = `Loan Application Update (${application.id})`;
  const body = [
    `Hello ${application.fullName},`,
    ``,
    `Your loan application has been processed.`,
    `Decision: ${decision.status.toUpperCase()}`,
    `Reason: ${decision.reason}`,
    ``,
    `Application ID: ${decision.applicationId}`,
    `Requested Amount: $${decision.requestedAmount.toFixed(2)}`,
    ``,
    `Thank you.`,
  ].join("\n");

  await sendEmail(application.email, subject, body);
}

