type SeoMetadata = {
  title: string;
  metaDescription: string;
  keywords: string[];
  slug: string;
};

type FinalPost = {
  content: string;
  seo: SeoMetadata;
  publishedAt: string;
};

async function runSpellGrammarCheck(draft: string): Promise<string> {
  const result = await llmExtract(draft, {
    correctedText: "string",
  });
  return result.correctedText ?? draft;
}

async function generateSeoMetadata(draft: string): Promise<SeoMetadata> {
  const result = await llmExtract(draft, {
    title: "string",
    metaDescription: "string",
    keywords: ["string"],
    slug: "string",
  });

  return {
    title: result.title ?? "Untitled Post",
    metaDescription: result.metaDescription ?? "",
    keywords: Array.isArray(result.keywords) ? result.keywords : [],
    slug: result.slug ?? "untitled-post",
  };
}

function mergePost(correctedText: string, seo: SeoMetadata): FinalPost {
  return {
    content: correctedText,
    seo,
    publishedAt: new Date().toISOString(),
  };
}

async function publishToCms(post: FinalPost): Promise<any> {
  return fetchFromApi("https://cms.example.com/posts", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(post),
  });
}

export async function processAndPublishBlogPost(draft: string): Promise<any> {
  const [correctedText, seoMetadata] = await Promise.all([
    runSpellGrammarCheck(draft),
    generateSeoMetadata(draft),
  ]);

  const finalPost = mergePost(correctedText, seoMetadata);
  return publishToCms(finalPost);
}

