type ShipmentItem = {
  description: string;
  quantity: number;
  unitValue: number;
  hsCode: string;
  originCountry: string;
};

type ShipmentRequest = {
  requestId: string;
  shipperName: string;
  recipientName: string;
  recipientAddress: string;
  destinationCountry: string;
  originCountry: string;
  weightKg: number;
  dimensionsCm: { length: number; width: number; height: number };
  items: ShipmentItem[];
};

type CarrierRate = {
  carrier: string;
  service: string;
  rate: number;
  currency: string;
  etaDays: number;
};

type CustomsDeclaration = {
  declarationId: string;
  destinationCountry: string;
  originCountry: string;
  totalDeclaredValue: number;
  lines: Array<{
    description: string;
    quantity: number;
    hsCode: string;
    unitValue: number;
    lineValue: number;
    originCountry: string;
  }>;
};

type ShippingLabel = {
  labelId: string;
  requestId: string;
  shipTo: string;
  shipToAddress: string;
  carrier: string;
  service: string;
  postageAmount: number;
  currency: string;
  etaDays: number;
  customsDeclarationId: string;
  customsSummary: string;
  status: "QUEUED_FOR_DISPATCH";
  createdAt: string;
};

async function calculateOptimalCarrierRate(
  request: ShipmentRequest
): Promise<CarrierRate> {
  const quotes: CarrierRate[] = await fetchFromApi("https://api.carrier-rates.local/quotes", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      originCountry: request.originCountry,
      destinationCountry: request.destinationCountry,
      weightKg: request.weightKg,
      dimensionsCm: request.dimensionsCm,
    }),
  });

  if (!quotes || quotes.length === 0) {
    throw new Error("No carrier quotes available");
  }

  return quotes.reduce((best, q) => (q.rate < best.rate ? q : best), quotes[0]);
}

async function generateCustomsDeclaration(
  request: ShipmentRequest
): Promise<CustomsDeclaration> {
  const lines = request.items.map((item) => ({
    description: item.description,
    quantity: item.quantity,
    hsCode: item.hsCode,
    unitValue: item.unitValue,
    lineValue: item.quantity * item.unitValue,
    originCountry: item.originCountry,
  }));

  const totalDeclaredValue = lines.reduce((sum, l) => sum + l.lineValue, 0);

  return {
    declarationId: `CD-${request.requestId}-${Date.now()}`,
    destinationCountry: request.destinationCountry,
    originCountry: request.originCountry,
    totalDeclaredValue,
    lines,
  };
}

function buildFinalShippingLabel(
  request: ShipmentRequest,
  rate: CarrierRate,
  customs: CustomsDeclaration
): ShippingLabel {
  return {
    labelId: `LBL-${request.requestId}-${Date.now()}`,
    requestId: request.requestId,
    shipTo: request.recipientName,
    shipToAddress: request.recipientAddress,
    carrier: rate.carrier,
    service: rate.service,
    postageAmount: rate.rate,
    currency: rate.currency,
    etaDays: rate.etaDays,
    customsDeclarationId: customs.declarationId,
    customsSummary: `${customs.lines.length} items, declared value ${customs.totalDeclaredValue}`,
    status: "QUEUED_FOR_DISPATCH",
    createdAt: new Date().toISOString(),
  };
}

async function queueForDispatch(label: ShippingLabel): Promise<void> {
  await writeToDatabase("dispatch_queue", {
    labelId: label.labelId,
    requestId: label.requestId,
    payload: label,
    status: label.status,
    queuedAt: new Date().toISOString(),
  });

  await logToAudit({
    event: "SHIPMENT_QUEUED",
    labelId: label.labelId,
    requestId: label.requestId,
    timestamp: new Date().toISOString(),
  });
}

export async function processShipmentRequest(
  request: ShipmentRequest
): Promise<ShippingLabel> {
  const [bestRate, customsDeclaration] = await Promise.all([
    calculateOptimalCarrierRate(request),
    generateCustomsDeclaration(request),
  ]);

  const finalLabel = buildFinalShippingLabel(request, bestRate, customsDeclaration);
  await queueForDispatch(finalLabel);

  return finalLabel;
}

