type TemperatureReading = number | { temperature: number; sensorId?: string; timestamp?: string };

function extractTemperature(reading: TemperatureReading): number {
  return typeof reading === "number" ? reading : reading.temperature;
}

async function monitorTemperatureStream(
  stream: AsyncIterable<TemperatureReading>,
  thresholdF: number = 80,
  windowSize: number = 10
): Promise<void> {
  const window: number[] = [];
  let sum = 0;

  for await (const reading of stream) {
    const temp = extractTemperature(reading);

    window.push(temp);
    sum += temp;

    if (window.length > windowSize) {
      const removed = window.shift()!;
      sum -= removed;
    }

    const avg = sum / window.length;

    if (avg > thresholdF) {
      await sendPushNotification(
        `Temperature alert: ${avg.toFixed(2)}°F average over last ${window.length} readings`
      );
    }
  }
}

async function main() {
  const stream = connectWebSocket("wss://sensors.example.com/temperature");
  await monitorTemperatureStream(stream, 80, 10);
}

{
  "name": "ip-rate-limiter",
  "nodes": {
    "incomingRequests": {
      "type": "producer",
      "source": "http-server",
      "config": {
        "port": 8080,
        "path": "/api"
      }
    },
    "requestWithIp": {
      "type": "derived",
      "deps": ["incomingRequests"],
      "fn": "regexExtractFields",
      "config": {
        "patterns": {
          "clientIp": "(?:x-forwarded-for[:=]\\s*)?([0-9]{1,3}(?:\\.[0-9]{1,3}){3})"
        }
      }
    },
    "rateLimitDecision": {
      "type": "derived",
      "deps": ["requestWithIp"],
      "fn": "transformPayload",
      "config": {
        "template": "Maintain per-clientIp timestamps for a 60-second sliding window; prune entries older than 60s; compute count60s; set limited=true when count60s>100; output { request, clientIp, count60s, limited }"
      }
    },
    "reject429": {
      "type": "effect",
      "deps": ["rateLimitDecision"],
      "fn": "sendResponse",
      "config": {
        "status": 429,
        "template": "Too Many Requests",
        "when": "limited == true"
      }
    },
    "handleAllowed": {
      "type": "effect",
      "deps": ["rateLimitDecision"],
      "fn": "handleRequest",
      "config": {
        "when": "limited == false"
      }
    }
  }
}

type RateLimitResult = {
  status: number;
  body: string;
};

const WINDOW_MS = 60_000;
const MAX_REQUESTS_PER_WINDOW = 100;

const requestsByIp = new Map<string, number[]>();

function pruneOldRequests(ip: string, now: number): number[] {
  const timestamps = requestsByIp.get(ip) ?? [];
  while (timestamps.length > 0 && now - timestamps[0] >= WINDOW_MS) {
    timestamps.shift();
  }

  if (timestamps.length === 0) {
    requestsByIp.delete(ip);
    return [];
  }

  requestsByIp.set(ip, timestamps);
  return timestamps;
}

function isRateLimited(ip: string, now = Date.now()): boolean {
  const timestamps = pruneOldRequests(ip, now);
  return timestamps.length >= MAX_REQUESTS_PER_WINDOW;
}

function recordRequest(ip: string, now = Date.now()): void {
  const timestamps = pruneOldRequests(ip, now);
  timestamps.push(now);
  requestsByIp.set(ip, timestamps);
}

export function handleIncomingRequest(clientIp: string): RateLimitResult {
  const now = Date.now();

  if (isRateLimited(clientIp, now)) {
    return {
      status: 429,
      body: "Too Many Requests",
    };
  }

  recordRequest(clientIp, now);

  return {
    status: 200,
    body: "OK",
  };
}

export function resetRateLimiter(): void {
  requestsByIp.clear();
}

