type CartEvent =
  | {
      type: 'add';
      item: { id: string; name: string; price: number };
      quantity?: number;
    }
  | {
      type: 'remove';
      itemId: string;
      quantity?: number;
    };

type CartItem = {
  id: string;
  name: string;
  price: number;
  quantity: number;
};

type CartState = Record<string, CartItem>;

type CartSummary = {
  items: CartItem[];
  itemCount: number;
  subtotal: number;
  tax: number;
  shipping: number;
  total: number;
};

const DEFAULT_TAX_RATE = 0.0825;

function round2(value: number): number {
  return Math.round(value * 100) / 100;
}

function applyCartEvent(state: CartState, event: CartEvent): CartState {
  const next: CartState = { ...state };

  if (event.type === 'add') {
    const qty = Math.max(1, event.quantity ?? 1);
    const existing = next[event.item.id];
    next[event.item.id] = existing
      ? {
          ...existing,
          price: event.item.price,
          name: event.item.name,
          quantity: existing.quantity + qty,
        }
      : {
          id: event.item.id,
          name: event.item.name,
          price: event.item.price,
          quantity: qty,
        };
  } else {
    const qty = Math.max(1, event.quantity ?? 1);
    const existing = next[event.itemId];
    if (!existing) return next;

    const remaining = existing.quantity - qty;
    if (remaining > 0) {
      next[event.itemId] = { ...existing, quantity: remaining };
    } else {
      delete next[event.itemId];
    }
  }

  return next;
}

function estimateShipping(subtotal: number, itemCount: number): number {
  if (itemCount === 0) return 0;
  if (subtotal >= 75) return 0;
  return round2(4.99 + itemCount * 0.5);
}

function computeCartSummary(state: CartState, taxRate = DEFAULT_TAX_RATE): CartSummary {
  const items = Object.values(state).sort((a, b) => a.name.localeCompare(b.name));
  const itemCount = items.reduce((acc, i) => acc + i.quantity, 0);
  const subtotal = round2(items.reduce((acc, i) => acc + i.price * i.quantity, 0));
  const tax = round2(subtotal * taxRate);
  const shipping = estimateShipping(subtotal, itemCount);
  const total = round2(subtotal + tax + shipping);

  return { items, itemCount, subtotal, tax, shipping, total };
}

async function pushCartSummaryToFrontend(summary: CartSummary): Promise<void> {
  await sendPushNotification(JSON.stringify({ type: 'cart.updated', payload: summary }));
}

async function processCartEvents(
  events: AsyncIterable<CartEvent>,
  pushUpdate: (summary: CartSummary) => Promise<void> = pushCartSummaryToFrontend,
  taxRate = DEFAULT_TAX_RATE
): Promise<void> {
  let state: CartState = {};

  for await (const event of events) {
    state = applyCartEvent(state, event);
    const summary = computeCartSummary(state, taxRate);
    await pushUpdate(summary);
  }
}

async function* cartEventsFromWebSocket(url: string): AsyncIterable<CartEvent> {
  for await (const raw of connectWebSocket(url)) {
    const event: CartEvent =
      typeof raw === 'string' ? (JSON.parse(raw) as CartEvent) : (raw as CartEvent);
    yield event;
  }
}

async function startCartRealtimeSync(eventsUrl: string): Promise<void> {
  await processCartEvents(cartEventsFromWebSocket(eventsUrl));
}

