type ScoreEvent = {
  playerId: string;
  score?: number; // absolute score
  delta?: number; // incremental score
};

type LeaderboardEntry = {
  rank: number;
  playerId: string;
  score: number;
};

type ConnectedClient = {
  id: string;
  send: (message: string) => Promise<void> | void;
};

function computeTopLeaderboard(
  scores: Map<string, number>,
  limit: number = 10
): LeaderboardEntry[] {
  return Array.from(scores.entries())
    .sort((a, b) => {
      if (b[1] !== a[1]) return b[1] - a[1];
      return a[0].localeCompare(b[0]);
    })
    .slice(0, limit)
    .map(([playerId, score], index) => ({
      rank: index + 1,
      playerId,
      score,
    }));
}

function leaderboardChanged(
  prev: LeaderboardEntry[],
  next: LeaderboardEntry[]
): boolean {
  if (prev.length !== next.length) return true;
  for (let i = 0; i < prev.length; i++) {
    if (
      prev[i].rank !== next[i].rank ||
      prev[i].playerId !== next[i].playerId ||
      prev[i].score !== next[i].score
    ) {
      return true;
    }
  }
  return false;
}

async function broadcastLeaderboard(
  clients: Set<ConnectedClient>,
  leaderboard: LeaderboardEntry[]
): Promise<void> {
  const payload = JSON.stringify({
    type: "leaderboard:update",
    leaderboard,
    updatedAt: new Date().toISOString(),
  });

  const results = await Promise.allSettled(
    Array.from(clients).map(async (client) => {
      await client.send(payload);
    })
  );

  const clientList = Array.from(clients);
  for (let i = 0; i < results.length; i++) {
    if (results[i].status === "rejected") {
      clients.delete(clientList[i]);
    }
  }
}

function applyScoreEvent(
  scores: Map<string, number>,
  event: ScoreEvent
): void {
  const current = scores.get(event.playerId) ?? 0;

  if (typeof event.delta === "number") {
    scores.set(event.playerId, current + event.delta);
    return;
  }

  if (typeof event.score === "number") {
    scores.set(event.playerId, event.score);
  }
}

async function processScoreEvents(
  scoreEvents: AsyncIterable<ScoreEvent>,
  clients: Set<ConnectedClient>,
  topN: number = 10
): Promise<void> {
  const scores = new Map<string, number>();
  let currentLeaderboard: LeaderboardEntry[] = [];

  for await (const event of scoreEvents) {
    applyScoreEvent(scores, event);

    const nextLeaderboard = computeTopLeaderboard(scores, topN);
    if (leaderboardChanged(currentLeaderboard, nextLeaderboard)) {
      currentLeaderboard = nextLeaderboard;
      await broadcastLeaderboard(clients, currentLeaderboard);
    }
  }
}

function addClient(clients: Set<ConnectedClient>, client: ConnectedClient): void {
  clients.add(client);
}

function removeClient(clients: Set<ConnectedClient>, clientId: string): void {
  for (const client of clients) {
    if (client.id === clientId) {
      clients.delete(client);
      break;
    }
  }
}

