type PricingApiResponse = {
  price: number;
  [key: string]: any;
};

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function fetchPriceFromApi(apiUrl: string): Promise<number> {
  const data = (await fetchFromApi(apiUrl)) as PricingApiResponse;
  if (!data || typeof data.price !== "number") {
    throw new Error("Invalid pricing API response");
  }
  return data.price;
}

async function getCachedPrice(cachePath: string): Promise<number> {
  const raw = await readFile(cachePath);
  const parsed = JSON.parse(raw);
  if (typeof parsed?.price !== "number") {
    throw new Error("Invalid cached price format");
  }
  return parsed.price;
}

async function getPriceWithRetry(
  apiUrl: string,
  cachePath: string,
  maxRetries: number = 3,
  baseDelayMs: number = 500
): Promise<number> {
  for (let attempt = 1; attempt <= maxRetries + 1; attempt++) {
    try {
      const price = await fetchPriceFromApi(apiUrl);
      await logToAudit({
        type: "pricing_attempt",
        attempt,
        status: "success",
        source: "api",
        price,
        timestamp: new Date().toISOString(),
      });
      return price;
    } catch (error: any) {
      const willRetry = attempt <= maxRetries;
      await logToAudit({
        type: "pricing_attempt",
        attempt,
        status: "failure",
        source: "api",
        willRetry,
        error: error?.message ?? String(error),
        timestamp: new Date().toISOString(),
      });

      if (willRetry) {
        const delay = baseDelayMs * 2 ** (attempt - 1);
        await sleep(delay);
      }
    }
  }

  try {
    const cachedPrice = await getCachedPrice(cachePath);
    await logToAudit({
      type: "pricing_fallback",
      status: "success",
      source: "cache",
      price: cachedPrice,
      timestamp: new Date().toISOString(),
    });
    return cachedPrice;
  } catch (error: any) {
    await logToAudit({
      type: "pricing_fallback",
      status: "failure",
      source: "cache",
      error: error?.message ?? String(error),
      timestamp: new Date().toISOString(),
    });
    throw new Error("Pricing API failed after retries and cache fallback failed");
  }
}

async function main() {
  const price = await getPriceWithRetry(
    "https://api.example.com/pricing/current",
    "./cache/price.json"
  );
  await logToAudit({
    type: "pricing_final",
    status: "resolved",
    price,
    timestamp: new Date().toISOString(),
  });
}

