type BreakerState = 'CLOSED' | 'OPEN';

type PaymentRequest = {
  id: string;
  amount: number;
  currency: string;
  source: string;
};

type PaymentResponse = {
  ok: boolean;
  status: 'approved' | 'declined' | 'degraded' | 'error';
  message: string;
  data?: any;
};

type Outcome = {
  ts: number;
  success: boolean;
};

const WINDOW_MS = 30_000;
const OPEN_MS = 10_000;

const outcomeWindow: Outcome[] = [];

let breakerState: BreakerState = 'CLOSED';
let openedAt = 0;
let probeInFlight = false;
let probeAttemptedAfterOpen = false;

function nowMs(): number {
  return Date.now();
}

function pruneWindow(now: number): void {
  while (outcomeWindow.length > 0 && now - outcomeWindow[0].ts > WINDOW_MS) {
    outcomeWindow.shift();
  }
}

function recordOutcome(success: boolean): void {
  const now = nowMs();
  outcomeWindow.push({ ts: now, success });
  pruneWindow(now);
}

function failureRate(): number {
  const now = nowMs();
  pruneWindow(now);
  if (outcomeWindow.length === 0) return 0;
  let failures = 0;
  for (const o of outcomeWindow) {
    if (!o.success) failures++;
  }
  return failures / outcomeWindow.length;
}

function shouldOpenBreaker(): boolean {
  return failureRate() > 0.5;
}

function openBreaker(): void {
  breakerState = 'OPEN';
  openedAt = nowMs();
  probeInFlight = false;
  probeAttemptedAfterOpen = false;
}

function closeBreaker(): void {
  breakerState = 'CLOSED';
  openedAt = 0;
  probeInFlight = false;
  probeAttemptedAfterOpen = false;
}

function degradedResponse(): PaymentResponse {
  return {
    ok: false,
    status: 'degraded',
    message: 'Payment service temporarily unavailable; using degraded response.',
  };
}

async function callDownstreamGateway(req: PaymentRequest): Promise<any> {
  return fetchFromApi('https://downstream-payments.example.com/charge', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(req),
  });
}

function isGatewaySuccess(result: any): boolean {
  return Boolean(result && (result.success === true || result.status === 'approved'));
}

export async function handlePayment(req: PaymentRequest): Promise<PaymentResponse> {
  if (breakerState === 'OPEN') {
    const elapsed = nowMs() - openedAt;
    if (elapsed < OPEN_MS) {
      return degradedResponse();
    }
    if (probeInFlight || probeAttemptedAfterOpen) {
      return degradedResponse();
    }

    probeInFlight = true;
    probeAttemptedAfterOpen = true;

    try {
      const result = await callDownstreamGateway(req);
      const success = isGatewaySuccess(result);
      recordOutcome(success);

      if (success) {
        closeBreaker();
        return {
          ok: true,
          status: 'approved',
          message: 'Probe succeeded; circuit closed.',
          data: result,
        };
      } else {
        openBreaker();
        return degradedResponse();
      }
    } catch {
      recordOutcome(false);
      openBreaker();
      return degradedResponse();
    } finally {
      probeInFlight = false;
    }
  }

  try {
    const result = await callDownstreamGateway(req);
    const success = isGatewaySuccess(result);
    recordOutcome(success);

    if (!success && shouldOpenBreaker()) {
      openBreaker();
    }

    return success
      ? { ok: true, status: 'approved', message: 'Payment processed.', data: result }
      : { ok: false, status: 'declined', message: 'Payment declined.', data: result };
  } catch {
    recordOutcome(false);
    if (shouldOpenBreaker()) {
      openBreaker();
    }
    return { ok: false, status: 'error', message: 'Gateway request failed.' };
  }
}

