type JobMessage = {
  id?: string;
  [key: string]: any;
};

const MAX_RETRIES = 2;
const OPS_CHANNEL = "#ops";
const DEAD_LETTER_TABLE = "dead_letter_queue";

export async function consumeJobQueue(
  jobQueue: AsyncIterable<JobMessage>,
  processFn: (message: JobMessage) => Promise<void>
): Promise<void> {
  for await (const message of jobQueue) {
    await processWithRetries(message, processFn, MAX_RETRIES);
  }
}

export async function processWithRetries(
  message: JobMessage,
  processFn: (message: JobMessage) => Promise<void>,
  maxRetries: number = 2
): Promise<void> {
  let attempt = 0;
  let lastError: unknown = null;

  while (attempt <= maxRetries) {
    try {
      await processFn(message);
      return;
    } catch (error) {
      lastError = error;
      attempt += 1;

      if (attempt > maxRetries) {
        const reason = getErrorReason(lastError);
        await moveToDeadLetterQueue(message, reason, attempt);
        await alertOps(message, reason, attempt);
        return;
      }
    }
  }
}

export async function moveToDeadLetterQueue(
  message: JobMessage,
  reason: string,
  attempts: number
): Promise<void> {
  await writeToDatabase(DEAD_LETTER_TABLE, {
    messageId: message.id ?? null,
    message,
    failureReason: reason,
    attempts,
    failedAt: new Date().toISOString(),
  });
}

export async function alertOps(
  message: JobMessage,
  reason: string,
  attempts: number
): Promise<void> {
  const messageId = message.id ?? "unknown";
  await sendSlackMessage(
    OPS_CHANNEL,
    `:rotating_light: Job failed after ${attempts} attempts. messageId=${messageId}. Reason: ${reason}`
  );
}

function getErrorReason(error: unknown): string {
  if (error instanceof Error) return error.message;
  try {
    return JSON.stringify(error);
  } catch {
    return String(error);
  }
}

