type NewUser = {
  id: string;
  email: string;
  name?: string;
  createdAt?: string;
};

function isValidEmail(email: string): boolean {
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(email);
}

function buildVerificationLink(userId: string): string {
  return `https://app.example.com/verify?userId=${encodeURIComponent(userId)}`;
}

async function runStep(
  stepName: string,
  fn: () => Promise<void>,
  context: Record<string, any>
): Promise<void> {
  try {
    await fn();
  } catch (error: any) {
    await logToAudit({
      event: "signup_step_failed",
      step: stepName,
      context,
      error: error?.message ?? String(error),
      timestamp: new Date().toISOString(),
    });
  }
}

export async function handleNewUserSignup(user: NewUser): Promise<void> {
  if (!isValidEmail(user.email)) {
    await logToAudit({
      event: "signup_rejected_invalid_email",
      userId: user.id,
      email: user.email,
      timestamp: new Date().toISOString(),
    });
    return;
  }

  const verificationLink = buildVerificationLink(user.id);

  await runStep(
    "create_user_record",
    async () => {
      await writeToDatabase("users", {
        id: user.id,
        email: user.email,
        name: user.name ?? null,
        createdAt: user.createdAt ?? new Date().toISOString(),
        emailVerified: false,
      });
    },
    { userId: user.id, email: user.email }
  );

  await runStep(
    "send_welcome_email",
    async () => {
      await sendEmail(
        user.email,
        "Welcome! Verify your email",
        `Hi${user.name ? ` ${user.name}` : ""}, welcome! Please verify your email by clicking: ${verificationLink}`
      );
    },
    { userId: user.id, email: user.email }
  );

  await runStep(
    "enqueue_analytics_event",
    async () => {
      await writeToDatabase("analytics_events", {
        type: "user_signed_up",
        userId: user.id,
        email: user.email,
        occurredAt: new Date().toISOString(),
      });
    },
    { userId: user.id, email: user.email }
  );

  await runStep(
    "provision_default_workspace",
    async () => {
      await writeToDatabase("workspaces", {
        id: `ws_${user.id}`,
        ownerUserId: user.id,
        name: "My Workspace",
        plan: "free",
        createdAt: new Date().toISOString(),
      });
    },
    { userId: user.id, email: user.email }
  );
}
